from django.utils.xmlUtils import xmlstring, get_node
from lxml import etree, html
from django_saml2.settings import SAML2_CONFIG as saml2_config
from django_saml2.saml import bindings, assertions, attributes, utils
import requests

@csrf_exempt
def saml_callback(request):
    # Check if the request method is POST and validate the signature
    if request.method != 'POST':
        return HttpResponse('Invalid Request', status=400)

    # Get SAML response as a string
    response = request.body.decode()

    # Validate the XML structure and signature
    try:
        saml_doc = etree.fromstring(response, parser=etree.XMLParser(resolve_entities=False))
        assert utils.validate_signature(saml2_config['entityid'], saml_doc, saml2_config['privatekey'])
    except Exception as e:
        return HttpResponse('Invalid SAML Response: ' + str(e), status=401)

    # Parse the assertion from the SAML response
    assertion = assertions.Assertion(saml_doc)

