    nameid = assertion.attributes.get_nameid()
    attributes_dict = {attr.name: attr.values for attr in assertion.attributes if 'attribute' in str(attr)}

    # Create a new user based on the extracted information
    user = create_user(**{
        'username': nameid,
        'email': attributes_dict.get('email', ''),
        'first_name': attributes_dict.get('givenName', ''),
        'last_name': attributes_dict.get('familyName', ''),
    })

    # Login the new user and save session data (additional steps not shown)
